Allows to format cursor off style instead only removal.

Example:
.terminal-cursor.off {
  visibility: visible;
  opacity: 0.5;
}

The original look is the default, so all still the same without extra user css.

e.g:

```bash
              that.stage.setOrientation(old_orientation);
              representations.forEach(function(repr) {
-                 // TODO: keep eye on this
-                 component.addRepresentation(repr.repr.type, repr.repr.params);
+                 var repr_name = repr.name;
+                 var repr_params = repr.repr.getParameters();
+                 // Note: not using repr.repr.type, repr.repr.params
+                 // since seems to me that repr.repr.params won't return correct "sele"
+                 component.addRepresentation(repr_name, repr_params);
```

def dynamic_content_item_variant_delete(self, id, id, **kwargs):
    "http://developer.zendesk.com/rest_api/docs/core/dynamic_content"
    api_path = "/api/v2/dynamic_content/items/{id}/variants/{id}.json"
    api_path = api_path.format(id=id, id=id)
    return self.call(api_path, method="DELETE", **kwargs)

def dynamic_content_item_variant_show(self, id, id, **kwargs):
    "http://developer.zendesk.com/rest_api/docs/core/dynamic_content"
    api_path = "/api/v2/dynamic_content/items/{id}/variants/{id}.json"
    api_path = api_path.format(id=id, id=id)
    return self.call(api_path, **kwargs)

def dynamic_content_item_variant_update(self, id, id, data, **kwargs):
    "http://developer.zendesk.com/rest_api/docs/core/dynamic_content"
    api_path = "/api/v2/dynamic_content/items/{id}/variants/{id}.json"
    api_path = api_path.format(id=id, id=id)
    return self.call(api_path, method="PUT", data=data, **kwargs)

